1	"use client";
2	
3	import { Box } from "@customink/pigment-react";
4	import IconButton from "@/components/ui/icon-button/icon-button";
5	import ArrowDownIcon from "@/components/ui/icons/arrow-down-icon";
6	import { ReactNode, useState, useEffect, useCallback, useMemo } from "react";
7	import styles from "./carousel-cards-view.module.css";
8	import { pdpRecommendations } from "@/lib/analytics/events/pdp";
9	
10	const SLIDES_PER_VIEW = 4;
11	const SLIDE_WIDTH = 100 / SLIDES_PER_VIEW; // 25%
12	
13	interface CarouselCardsViewProps {
14	  children: ReactNode[];
15	}
16	
17	export default function CarouselCardsView({ children }: CarouselCardsViewProps) {
18	  const total = children.length;
19	  const [index, setIndex] = useState(0);
20	  const [animate, setAnimate] = useState(true);
21	  const [isAnimating, setIsAnimating] = useState(false);
22	
23	  // Reset position when content changes (tab switch)
24	  useEffect(() => {
25	    setAnimate(false);
26	    setIndex(0);
27	  }, [total]);
28	
29	  // Re-enable transitions after an instant jump
30	  useEffect(() => {
31	    if (!animate) {
32	      requestAnimationFrame(() => {
33	        requestAnimationFrame(() => {
34	          setAnimate(true);
35	          setIsAnimating(false);
36	        });
37	      });
38	    }
39	  }, [animate]);
40	
41	  // Clone slides at edges for seamless looping:
42	  // [last N clones] [real slides] [first N clones]
43	  const slides = useMemo(
44	    () => [
45	      ...children.slice(-SLIDES_PER_VIEW).map((child, i) => ({ child, key: `clone-end-${i}` })),
46	      ...children.map((child, i) => ({ child, key: `real-${i}` })),
47	      ...children.slice(0, SLIDES_PER_VIEW).map((child, i) => ({ child, key: `clone-start-${i}` })),
48	    ],
49	    [children],
50	  );
51	
52	  // Offset accounts for the prepended clones
53	  const trackOffset = (index + SLIDES_PER_VIEW) * SLIDE_WIDTH;
54	
55	  const handleTransitionEnd = useCallback(
56	    (e: React.TransitionEvent) => {
57	      if (e.target !== e.currentTarget) return;
58	      setIsAnimating(false);
59	      if (index >= total) {
60	        setAnimate(false);
61	        setIndex(index % total);
62	      } else if (index < 0) {
63	        setAnimate(false);
64	        setIndex(((index % total) + total) % total);
65	      }
66	    },
67	    [index, total],
68	  );
69	
70	  const handlePrev = (e: React.MouseEvent): void => {
71	    if (isAnimating) return;
72	    e.stopPropagation();
73	    setIsAnimating(true);
74	    pdpRecommendations.tabbedViewArrowClick("prev");
75	    setIndex((prev) => prev - 1);
76	  };
77	
78	  const handleNext = (e: React.MouseEvent): void => {
79	    if (isAnimating) return;
80	    e.stopPropagation();
81	    setIsAnimating(true);
82	    pdpRecommendations.tabbedViewArrowClick("next");
83	    setIndex((prev) => prev + 1);
84	  };
85	
86	  const showArrows = total > SLIDES_PER_VIEW;
87	
88	  return (
89	    <Box className={styles.carouselWrapper} data-testid="pdp-reco-carousel">
90	      {showArrows && (
91	        <Box display="flex" className={styles.arrowOverlay}>
92	          <IconButton
93	            aria-label="Previous slide"
94	            onClick={handlePrev}
95	            className={styles.arrowBtn}
96	            data-testid="pdp-reco-carousel-prev"
97	          >
98	            <ArrowDownIcon className={styles.arrowPrev} />
99	          </IconButton>
100	
101	          <IconButton
102	            aria-label="Next slide"
103	            onClick={handleNext}
104	            className={styles.arrowBtn}
105	            data-testid="pdp-reco-carousel-next"
106	          >
107	            <ArrowDownIcon className={styles.arrowNext} />
108	          </IconButton>
109	        </Box>
110	      )}
111	
112	      <Box className={styles.viewport}>
113	        <Box
114	          className={styles.track}
115	          style={{
116	            transform: `translateX(-${trackOffset}%)`,
117	            transition: animate ? "transform 0.6s ease" : "none",
118	          }}
119	          onTransitionEnd={handleTransitionEnd}
120	        >
121	          {slides.map(({ child, key }) => {
122	            const isClone = key.startsWith("clone-");
123	            return (
124	              <Box
125	                key={key}
126	                className={styles.slide}
127	                {...(isClone ? { "aria-hidden": true, tabIndex: -1 } : {})}
128	              >
129	                {child}
130	              </Box>
131	            );
132	          })}
133	        </Box>
134	      </Box>
135	    </Box>
136	  );
137	}
