1	"use client";
2	
3	import { RefObject, ReactNode } from "react";
4	import { RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE } from "@/constants/pdp-related-products";
5	import useIntersectionObserverOnce from "@/hooks/use-intersection-observer-once";
6	import ProductDetailsRow from "@/components/features/product-details-page/product-details-row";
7	import type { TabItem } from "@/components/ui/tabs/tabs";
8	import RelatedProductCard from "../related-product-card";
9	import addColorToStylePath from "../../utils/add-color-to-style-path";
10	import { pdpRecommendations } from "@/lib/analytics/events/pdp";
11	import type { RelatedProduct } from "@/types/related-products";
12	import CarouselCardsView from "./carousel-cards-view";
13	import EmptyStateCardsView from "./empty-state-cards-view";
14	import Loader from "./loader";
15	import StyledRecoBox from "./styled-reco-box";
16	import Tabs from "./tabs";
17	import cardStyles from "./tabbed-card-overrides.module.css";
18	
19	interface CardsComponentProps {
20	  children: ReactNode[];
21	  isLoading: boolean;
22	  length: number;
23	}
24	
25	function CardsComponent({ children, isLoading, length }: CardsComponentProps) {
26	  if (!isLoading && length === 0) {
27	    return <EmptyStateCardsView />;
28	  }
29	  if (isLoading) {
30	    return <Loader />;
31	  }
32	  if (length <= 4) {
33	    return <StyledRecoBox>{children}</StyledRecoBox>;
34	  }
35	  return <CarouselCardsView>{children}</CarouselCardsView>;
36	}
37	
38	interface RelatedProductsTabbedViewProps {
39	  activeTab?: string;
40	  hasAnyData?: boolean;
41	  isLoading: boolean;
42	  onTabChange?: (value: string) => void;
43	  products: RelatedProduct[];
44	  relatedProductsRef: RefObject<HTMLDivElement | null>;
45	  tabs: TabItem[];
46	}
47	
48	export default function RelatedProductsTabbedView({
49	  activeTab = RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
50	  hasAnyData = true,
51	  isLoading,
52	  onTabChange,
53	  products = [],
54	  relatedProductsRef,
55	  tabs = [],
56	}: RelatedProductsTabbedViewProps) {
57	  useIntersectionObserverOnce(relatedProductsRef, () => {
58	    pdpRecommendations.tabbedViewDisplay();
59	  });
60	
61	  const handleCardClick = (styleId: string | number, href: string | null) => {
62	    if (!href) return;
63	    pdpRecommendations.tabbedViewItemClick(activeTab, styleId, () => {
64	      window.location.href = href;
65	    });
66	  };
67	
68	  const shouldShow = hasAnyData || isLoading || tabs.length > 0;
69	  if (!shouldShow) {
70	    return null;
71	  }
72	
73	  const slides = products.map((product) => {
74	    const href = addColorToStylePath(product.link, product.color);
75	    return (
76	      <RelatedProductCard
77	        className={cardStyles.tabbedCard}
78	        imageClassName={cardStyles.tabbedImageWrapper}
79	        productNameClassName={cardStyles.tabbedProductName}
80	        priceContainerClassName={cardStyles.tabbedPriceContainer}
81	        cardContentClassName={cardStyles.tabbedCardContent}
82	        key={`related-styles-${activeTab.toLowerCase()}-${product.style_id}`}
83	        product={product}
84	        onClick={() => handleCardClick(product.style_id, href)}
85	      />
86	    );
87	  });
88	
89	  return (
90	    <div data-testid="pdp-related-products-tabbed-view">
91	      <ProductDetailsRow
92	        childrenRef={relatedProductsRef as RefObject<HTMLDivElement>}
93	        title="Recommended for you"
94	      >
95	        <Tabs tabs={tabs} activeTab={activeTab} onTabChange={onTabChange} />
96	        <div role="tabpanel" id={`tabpanel-${activeTab}`} aria-labelledby={`tab-${activeTab}`}>
97	          <CardsComponent key={activeTab} isLoading={isLoading} length={products.length}>
98	            {slides}
99	          </CardsComponent>
100	        </div>
101	      </ProductDetailsRow>
102	    </div>
103	  );
104	}
